 * by counting ampersands directly. Returns the count of ampersands which
 * equals the number of parameters minus one (matching body.split('&').length - 1).
 *
 * @param {string} body
 * @param {number} limit
 * @api private
 */

function parameterCount (body, limit) {
  var count = 0
  var pos = 0

  // Count ampersands (same as body.split('&').length - 1)
  while ((pos = body.indexOf('&', pos)) !== -1) {
    count++
    pos++
    // body.split('&').length > limit means count + 1 > limit, so count >= limit
    if (count >= limit) {
      return undefined
    }
  }

  return count
}

